  begin
    if (tok_id[0] = 'f') and (tok_id[1] = 'a') and (tok_id[2] = 'l')
       and (tok_id[3] = 's') and (tok_id[4] = 'e') then
      classify_ident := TK_FALSE
  end
end;

procedure lex_init;
var
  ch: char;
begin
  src_len := 0;
  pos := 0;
  tok := TK_EOF;
  tok_int := 0;
  tok_id_len := 0;

  while not eof do
  begin
    read(ch);
    if ch = chr(4) then
    begin
      { EOT marker }
    end
    else if src_len < SRC_MAX then
    begin
      src[src_len] := ch;
      src_len := src_len + 1
    end
  end
end;

procedure lex_next;
var
  c: char;
begin
  skip_ws_and_comments;

  if pos >= src_len then
  begin
    tok := TK_EOF;
    exit
  end;

  c := src[pos];

  if is_digit(c) then
  begin
    tok := TK_INT;
    tok_int := 0;
    while (pos < src_len) and is_digit(src[pos]) do
    begin
      tok_int := tok_int * 10 + (ord(src[pos]) - ord('0'));
      pos := pos + 1
    end;
    exit
  end;

  if is_alpha(c) then
  begin
    tok_id_len := 0;
    while (pos < src_len) and is_alnum(src[pos]) do
    begin
      if tok_id_len < ID_MAX then
      begin
        tok_id[tok_id_len] := src[pos];
        tok_id_len := tok_id_len + 1
      end;
      pos := pos + 1
    end;
    tok := classify_ident;
    exit
  end;

  case c of
    '+': begin tok := TK_PLUS;  pos := pos + 1 end;
    '*': begin tok := TK_STAR;  pos := pos + 1 end;
    '/': begin tok := TK_SLASH; pos := pos + 1 end;
    '(': begin tok := TK_LPAREN; pos := pos + 1 end;
    ')': begin tok := TK_RPAREN; pos := pos + 1 end;
    ';': begin tok := TK_SEMI;  pos := pos + 1 end;
    '-':
      begin
        pos := pos + 1;
        if (pos < src_len) and (src[pos] = '>') then
        begin
          tok := TK_ARROW;
          pos := pos + 1
        end
        else
          tok := TK_MINUS
      end;
    '=':
      begin
        tok := TK_EQ;
        pos := pos + 1
      end;
    '<':
      begin
        pos := pos + 1;
        if (pos < src_len) and (src[pos] = '>') then
        begin
          tok := TK_NEQ;
          pos := pos + 1
        end
        else if (pos < src_len) and (src[pos] = '=') then
        begin
          tok := TK_LE;
          pos := pos + 1
        end
        else
          tok := TK_LT
      end;
    '>':
      begin
        pos := pos + 1;
        if (pos < src_len) and (src[pos] = '=') then
        begin
          tok := TK_GE;
          pos := pos + 1
        end
        else
          tok := TK_GT
      end;
    '&':
      begin
        pos := pos + 1;
        if (pos < src_len) and (src[pos] = '&') then
        begin
          tok := TK_ANDAND;
          pos := pos + 1
        end
        else
        begin
          tok := TK_ERROR;
          pos := pos + 1
        end
      end;
    '|':
      begin
        pos := pos + 1;
        if (pos < src_len) and (src[pos] = '|') then
        begin
          tok := TK_OROR;
          pos := pos + 1
        end
        else
        begin
          tok := TK_ERROR;
          pos := pos + 1
        end
      end
  else
    begin
      tok := TK_ERROR;
      pos := pos + 1
    end
  end
end;

{ --- Print token name --- }

procedure print_tok_name;
begin
  case tok of
    TK_EOF:    write('EOF');
    TK_INT:    write('INT');
    TK_IDENT:  write('IDENT');
    TK_LET:    write('LET');
    TK_REC:    write('REC');
    TK_IN:     write('IN');
    TK_IF:     write('IF');
    TK_THEN:   write('THEN');
    TK_ELSE:   write('ELSE');
    TK_FUN:    write('FUN');
    TK_TRUE:   write('TRUE');
    TK_FALSE:  write('FALSE');
    TK_NOT:    write('NOT');
    TK_MOD:    write('MOD');
    TK_PLUS:   write('PLUS');
    TK_MINUS:  write('MINUS');
    TK_STAR:   write('STAR');
    TK_SLASH:  write('SLASH');
    TK_EQ:     write('EQ');
    TK_NEQ:    write('NEQ');
    TK_LT:     write('LT');
    TK_GT:     write('GT');
    TK_LE:     write('LE');
    TK_GE:     write('GE');
    TK_ANDAND: write('ANDAND');
    TK_OROR:   write('OROR');
    TK_ARROW:  write('ARROW');
    TK_LPAREN: write('LPAREN');
    TK_RPAREN: write('RPAREN');
    TK_SEMI:   write('SEMI');
    TK_ERROR:  write('ERROR')
  end
end;

{ --- Main test --- }

begin
  lex_init;
  lex_next;
  while tok <> TK_EOF do
  begin
    print_tok_name;
    if tok = TK_INT then
    begin
      write(' ');
      writeln(tok_int)
    end
    else if (tok = TK_IDENT) or (tok = TK_LET) or (tok = TK_REC)
         or (tok = TK_IN) or (tok = TK_IF) or (tok = TK_THEN)
         or (tok = TK_ELSE) or (tok = TK_FUN) or (tok = TK_TRUE)
         or (tok = TK_FALSE) or (tok = TK_NOT) or (tok = TK_MOD) then
    begin
      write(' ');
      for i := 0 to tok_id_len - 1 do
        write(tok_id[i]);
      writeln
    end
    else
      writeln;
    lex_next
  end;
  writeln('EOF')
end.

