    if (tok_id[0] = 't') and (tok_id[1] = 'h') and (tok_id[2] = 'e')
       and (tok_id[3] = 'n') then
      classify_ident := TK_THEN
    else if (tok_id[0] = 'e') and (tok_id[1] = 'l') and (tok_id[2] = 's')
       and (tok_id[3] = 'e') then
      classify_ident := TK_ELSE
    else if (tok_id[0] = 't') and (tok_id[1] = 'r') and (tok_id[2] = 'u')
       and (tok_id[3] = 'e') then
      classify_ident := TK_TRUE
  end
  else if tok_id_len = 5 then
  begin
    if (tok_id[0] = 'f') and (tok_id[1] = 'a') and (tok_id[2] = 'l')
       and (tok_id[3] = 's') and (tok_id[4] = 'e') then
      classify_ident := TK_FALSE
  end
end;

{ --- Public interface --- }

procedure lex_init;
var
  ch: char;
begin
  src_len := 0;
  pos := 0;
  tok := TK_EOF;
  tok_int := 0;
  tok_id_len := 0;

  { Read entire input into src buffer }
  while not eof do
  begin
    read(ch);
    if ch = chr(4) then
    begin
      { EOT marker -- stop reading }
    end
    else if src_len < SRC_MAX then
    begin
      src[src_len] := ch;
      src_len := src_len + 1
    end
  end
end;

procedure lex_next;
var
  c: char;
begin
  skip_ws_and_comments;

  if pos >= src_len then
  begin
    tok := TK_EOF;
    exit
  end;

  c := src[pos];

  { Integer literal }
  if is_digit(c) then
  begin
    tok := TK_INT;
    tok_int := 0;
    while (pos < src_len) and is_digit(src[pos]) do
    begin
      tok_int := tok_int * 10 + (ord(src[pos]) - ord('0'));
      pos := pos + 1
    end;
    exit
  end;

  { Identifier or keyword }
  if is_alpha(c) then
  begin
    tok_id_len := 0;
    while (pos < src_len) and is_alnum(src[pos]) do
    begin
      if tok_id_len < ID_MAX then
      begin
        tok_id[tok_id_len] := src[pos];
        tok_id_len := tok_id_len + 1
      end;
      pos := pos + 1
    end;
    tok := classify_ident;
    exit
  end;

  { Operators and delimiters }
  case c of
    '+': begin tok := TK_PLUS;  pos := pos + 1 end;
    '*': begin tok := TK_STAR;  pos := pos + 1 end;
    '/': begin tok := TK_SLASH; pos := pos + 1 end;
    '(': begin tok := TK_LPAREN; pos := pos + 1 end;
    ')': begin tok := TK_RPAREN; pos := pos + 1 end;
    ';': begin tok := TK_SEMI;  pos := pos + 1 end;
    '-':
      begin
        pos := pos + 1;
        if (pos < src_len) and (src[pos] = '>') then
        begin
          tok := TK_ARROW;
          pos := pos + 1
        end
        else
          tok := TK_MINUS
      end;
    '=':
      begin
        tok := TK_EQ;
        pos := pos + 1
      end;
    '<':
      begin
        pos := pos + 1;
        if (pos < src_len) and (src[pos] = '>') then
        begin
          tok := TK_NEQ;
          pos := pos + 1
        end
        else if (pos < src_len) and (src[pos] = '=') then
        begin
          tok := TK_LE;
          pos := pos + 1
        end
        else
          tok := TK_LT
      end;
    '>':
      begin
        pos := pos + 1;
        if (pos < src_len) and (src[pos] = '=') then
        begin
          tok := TK_GE;
          pos := pos + 1
        end
        else
          tok := TK_GT
      end;
    '&':
      begin
        pos := pos + 1;
        if (pos < src_len) and (src[pos] = '&') then
        begin
          tok := TK_ANDAND;
          pos := pos + 1
        end
        else
        begin
          tok := TK_ERROR;
          pos := pos + 1
        end
      end;
    '|':
      begin
        pos := pos + 1;
        if (pos < src_len) and (src[pos] = '|') then
        begin
          tok := TK_OROR;
          pos := pos + 1
        end
        else
        begin
          tok := TK_ERROR;
          pos := pos + 1
        end
      end
  else
    begin
      tok := TK_ERROR;
      pos := pos + 1
    end
  end
end;

