      exit
    end;
    val_e := parse_expr;
    if tok = TK_IN then
      lex_next
    else
    begin
      set_parse_error('n');
      exit
    end;
    body_e := parse_expr;
    e := mk_let_node(val_e, body_e);
    restore_name_to(e);
    if is_rec then
      e^.ival := 1;  { flag: 1 = let rec }
    parse_expr := e;
    exit
  end;

  if tok = TK_IF then
  begin
    lex_next;
    val_e := parse_expr;
    if tok = TK_THEN then
      lex_next
    else
    begin
      set_parse_error('t');
      exit
    end;
    body_e := parse_expr;
    if tok = TK_ELSE then
      lex_next
    else
    begin
